<?php
 namespace WPAICG\AIPKit\Addons; if (!defined('ABSPATH')) { exit; } class AIPKit_IP_Anonymization { public static function maybe_anonymize(?string $ip, bool $enabled = false): ?string { if (empty($ip)) { return $ip; } if (!$enabled) { return $ip; } if (filter_var($ip, FILTER_VALIDATE_IP, FILTER_FLAG_IPV4)) { return self::_anonymize_ipv4($ip); } elseif (filter_var($ip, FILTER_VALIDATE_IP, FILTER_FLAG_IPV6)) { return self::_anonymize_ipv6($ip); } else { return $ip; } } private static function _anonymize_ipv4(string $ip): string { $parts = explode('.', $ip); if (count($parts) === 4) { $parts[3] = '0'; return implode('.', $parts); } return '0.0.0.0'; } private static function _anonymize_ipv6(string $ip): string { $packed_ip = @inet_pton($ip); if ($packed_ip === false) { return '::'; } $expanded_ip = inet_ntop($packed_ip); if ($expanded_ip === false) { return '::'; } $blocks = explode(':', $expanded_ip); if (count($blocks) === 8) { $blocks[7] = '0000'; } else { return '::'; } $anonymized_expanded = implode(':', $blocks); $anonymized_packed = @inet_pton($anonymized_expanded); if ($anonymized_packed === false) { return '::'; } $anonymized_compressed = inet_ntop($anonymized_packed); if ($anonymized_compressed === false) { return '::'; } return $anonymized_compressed; } } 